import{_ as a,c as e,a as n,o as i}from"./app-CEcM0piI.js";const t={};function l(d,s){return i(),e("div",null,s[0]||(s[0]=[n(`<p>在java中线程只有六种状态,没有运行状态,因为当线程进入运行状态时jvm虚拟机就将该线程交给cpu运行了,所以对于jvm虚拟机来说不需要有运行状态</p><h1 id="继承thread类的方法" tabindex="-1"><a class="header-anchor" href="#继承thread类的方法"><span>继承Thread类的方法</span></a></h1><p>要自定义一个类继承Thread类并重写run方法,当开启线程时自动执行run方法 使用start方法开启线程</p><p>可以调用Thread中的成员方法</p><p>成员方法</p><table><thead><tr><th>方法名称</th><th>说明</th></tr></thead><tbody><tr><td>String getName()</td><td>返回此线程的名称</td></tr><tr><td>void setName(String name)</td><td>设置线程的名字 (构造方法也可以设置名字)</td></tr><tr><td>staticc Thread currentThread()</td><td>获取当前线程的对象</td></tr><tr><td>staticc void sleep(long time)</td><td>让线程休眠指定的时间，单位为毫秒</td></tr><tr><td>setPriority(int newPriority)</td><td>设置线程的优先级</td></tr><tr><td>final int getPriority()</td><td>获取线程的优先级</td></tr><tr><td>final void setDaemon(boolean on)</td><td>设置为守护线程</td></tr><tr><td>public static void yield()</td><td>出让线程/礼让线程,当一个线程执行到该函数时就出让自己的执行权</td></tr><tr><td>public static void join()</td><td>插入线程/插队线程,先执行这个线程</td></tr></tbody></table><p>如果没有给线程设置名字它也是有默认名字的:Thread-编号 优先级越大抢到时间片的概率也越大,但并不意味着一定比它优先级低的线程先抢到 优先级从1到10,数字越大优先级越高 当非守护线程都执行完毕后会给守护线程发送一个信号,守护线程接收到信号后会陆续结束(并不是非守护线程结束瞬间结束)</p><h2 id="线程同步" tabindex="-1"><a class="header-anchor" href="#线程同步"><span>线程同步</span></a></h2><p>在多线程的场景下推荐使用StringBuffer,它和StringBuilder一样,但是线程安全的(所有的方法前都加了 synchronized 关键字修饰)</p><p>对于锁,因为java是面向对象的语言,很多时候一个对象都是写在一个类内部的,如果是锁对象写在类内部那么在多线程的场景下多个对象可能会有不同的锁,因此锁大多是使用static修饰的</p><h3 id="synchronized" tabindex="-1"><a class="header-anchor" href="#synchronized"><span>synchronized</span></a></h3><p><strong>同步代码块</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>synchronized(锁){</span></span>
<span class="line"><span>	操作共享数据的代码;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>锁默认打开，有一个线程进去了，锁自动关闭 里面的代码全部执行完毕，线程出来，锁自动打开 锁可以使用Object对象来指代 示例</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Object obj = new Object();</span></span>
<span class="line"><span></span></span>
<span class="line"><span>public void run(){</span></span>
<span class="line"><span>	while(true){</span></span>
<span class="line"><span>		//同步代码块</span></span>
<span class="line"><span>		synchronized(obj){}</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>同步函数</strong> 将synchronized关键字用于修饰函数使这个函数能够上锁 锁住方法里面所有的代码</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>修饰符 synchronized 返回值类型方法名(方法参数){}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>锁对象不能自己指定 如果是非静态方法锁对象就是this 如果是静态方法锁对象就是当前类的字节码文件对象</p><h1 id="实现runnable接口的方法" tabindex="-1"><a class="header-anchor" href="#实现runnable接口的方法"><span>实现Runnable接口的方法</span></a></h1><p>自定义一个类实现Runnable接口并重写run方法 使用start方法开启线程</p><h1 id="利用callable和future实现" tabindex="-1"><a class="header-anchor" href="#利用callable和future实现"><span>利用Callable和Future实现</span></a></h1><p>前两种方法都没有返回值,使用该方法可以获取多线程运行的结果 创建MyCallable类实现callable接口重写call方法（表示多线程要执行的任务） Future是一个抽象类所以不能创建对象可以创建它的实现对象FutureTask 创建FutureTask的对象（作用管理多线程运行的结果） 创建Thread类的对象，并启动（表示线程）</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public class MyCallable implements Calllabel&lt;Integer&gt;{</span></span>
<span class="line"><span>	@Override</span></span>
<span class="line"><span>	public Integer call(){}</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//创建MyCallable的对象（表示多线程要执行的任务）</span></span>
<span class="line"><span>MyCallable mc = new MyCallable();</span></span>
<span class="line"><span>//创建FutureTask的对象（作用管理多线程运行的结果）</span></span>
<span class="line"><span>FutureTask&lt;Integer&gt;ft = new FutureTask&lt;&gt;(mc);</span></span>
<span class="line"><span>//创建线程的对象</span></span>
<span class="line"><span>Thread t1 = new Thread(ft);</span></span>
<span class="line"><span>//启动线程</span></span>
<span class="line"><span>t1.start();</span></span>
<span class="line"><span>//获取多线程运行的结果</span></span>
<span class="line"><span>Integer result = ft.get();</span></span>
<span class="line"><span>System.out.println(result)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p><strong>手动上锁/释放锁</strong></p><p>获取lock对象再对其上锁</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Lock lock=new ReentrantLock();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>void lock(): 获得锁 void unlock()：释放锁</p><h4 id="唤醒" tabindex="-1"><a class="header-anchor" href="#唤醒"><span>唤醒</span></a></h4><p>锁的成员函数</p><table><thead><tr><th>方法名称</th><th>说明</th></tr></thead><tbody><tr><td>void wait()</td><td>当前线程等待，直到被其他线程唤醒</td></tr><tr><td>void notify()</td><td>随机唤醒单个线程</td></tr><tr><td>void notifyAll()</td><td>唤醒所有线程<br></td></tr></tbody></table><h4 id="阻塞队列" tabindex="-1"><a class="header-anchor" href="#阻塞队列"><span>阻塞队列</span></a></h4><p>将任务放到一个队列中,当队列满时生产者被阻塞,队列空时消费者被阻塞</p><p>阻塞队列实现了4个接口 Iterable Collection Queue BlockingQueue 这些接口不可直接创建对象</p><p>两个实现类 ArrayBlockingQueue底层是数组,有界 LinkedBlockingQueue底层是链表,无界</p><h2 id="线程池" tabindex="-1"><a class="header-anchor" href="#线程池"><span>线程池</span></a></h2><h4 id="通过工具类创建线程池" tabindex="-1"><a class="header-anchor" href="#通过工具类创建线程池"><span>通过工具类创建线程池</span></a></h4><p>可以方便的创建线程池</p><p>Executors:线程池的工具类通过调用方法返回不同类型的线程池对象</p><table><thead><tr><th>方法名称</th><th>说明</th></tr></thead><tbody><tr><td>public static ExecutorService newCachedThreadPool()</td><td>创建一个没有上限的线程池</td></tr><tr><td>public static ExecutorService newFixedThreadPool(int nThreads)</td><td>创建有上限的线程池</td></tr><tr><td>void submit(task())</td><td>提交任务函数给线程池让它运行</td></tr><tr><td>void shutdown()</td><td>销毁线程池</td></tr></tbody></table><h4 id="自定义线程池" tabindex="-1"><a class="header-anchor" href="#自定义线程池"><span>自定义线程池</span></a></h4><ul><li>参数一：核心线程数量不能小于0</li><li>参数二：最大线程数不能小于0，最大数量&gt;=核心线程数量</li><li>参数三：空闲线程最大存活时间不能小于0</li><li>参数四：时间单位用TimeUnit指定</li><li>参数五：任务队列不能为null</li><li>参数六：创建线程工厂不能为null</li><li>参数七：任务的拒绝策略不能为null</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ThreadPoolExecutor pool=new ThreadPoolExecutor(</span></span>
<span class="line"><span>	3,</span></span>
<span class="line"><span>	6,</span></span>
<span class="line"><span>	60,</span></span>
<span class="line"><span>	TimeUnit.SECONDS,</span></span>
<span class="line"><span>	new ArrayBlockingQueue&lt;&gt;(3),</span></span>
<span class="line"><span>	Executors.defaultThreadFactory(),</span></span>
<span class="line"><span>	new ThreadPoolExecutor.AbortPolicy()</span></span>
<span class="line"><span>);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,42)]))}const p=a(t,[["render",l]]),c=JSON.parse('{"path":"/back/java/6/","title":"6 多线程","lang":"zh-CN","frontmatter":{"title":"6 多线程","createTime":"2025/04/05 12:12:26","permalink":"/back/java/6/"},"readingTime":{"minutes":4.56,"words":1367},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/后端/Java/6 多线程.md","headers":[]}');export{p as comp,c as data};
